def _find_header_col(headers, column_name):
    wanted = _norm_sheet_col(column_name)
    for i, h in enumerate(headers, start=1):
        if _norm_sheet_col(h) == wanted:
            return i
    return None


def _gs_safe_value(value):
    """Convert pandas/numpy/date values into JSON-serializable values for gspread."""
    try:
        if pd.isna(value):
            return ""
    except Exception:
        pass

    try:
        if hasattr(value, "item") and not isinstance(value, (str, bytes)):
            value = value.item()
    except Exception:
        pass

    if isinstance(value, (pd.Timestamp, datetime)):
        return value.strftime("%d.%m.%Y %H:%M:%S")
    if isinstance(value, date):
        return value.strftime("%d.%m.%Y")
    if isinstance(value, time):
        return value.strftime("%H:%M")
    if isinstance(value, float):
        return round(float(value), 6)
    if isinstance(value, int):
        return int(value)
    return value


def _append_dict_to_sheet(sheet_name, row_dict, required_columns):
    ws = _get_kpi_worksheet(sheet_name)
    headers = _ensure_sheet_headers(ws, required_columns)
    row = [_gs_safe_value(row_dict.get(h, "")) for h in headers]
    ws.append_row(row, value_input_option="USER_ENTERED")


def _update_sheet_cells(sheet_name, row_number, updates, required_columns):
    ws = _get_kpi_worksheet(sheet_name)
    headers = _ensure_sheet_headers(ws, required_columns)
    for col_name, value in updates.items():
        col_idx = _find_header_col(headers, col_name)
        if col_idx is not None:
            ws.update_cell(int(row_number), col_idx, _gs_safe_value(value))


def _delete_sheet_rows(sheet_name, row_numbers):
    """Delete Google Sheet rows safely from bottom to top."""
    clean_rows = sorted({int(r) for r in row_numbers if str(r).strip()}, reverse=True)
    if not clean_rows:
        return 0
    ws = _get_kpi_worksheet(sheet_name)
    for row_num in clean_rows:
        if row_num >= 2:  # never delete header
            ws.delete_rows(row_num)
    return len(clean_rows)


def delete_work_ticket_and_related_activity(task_row):
    """Admin delete: remove a task regardless of status and remove matching activity rows.

    Matching activity rows use Assigned_To + Task_Title because the current simplified
    TASKS/TASK_ACTIVITY sheet structure does not include Task_ID.
    """
    task_row_number = int(task_row.get("_row"))
    assigned_to = str(task_row.get("Assigned_To", "") or "").strip()
    task_title = str(task_row.get("Task_Title", "") or "").strip()

    deleted_activities = 0
    activity_df, _ = load_task_activity_data()
    if not activity_df.empty:
        related = activity_df[
            activity_df["Assigned_To"].astype(str).str.strip().eq(assigned_to)
            & activity_df["Task_Title"].astype(str).str.strip().eq(task_title)
        ].copy()
        if not related.empty:
            deleted_activities = _delete_sheet_rows(TASK_ACTIVITY_SHEET_NAME, related["_row"].tolist())

    deleted_tasks = _delete_sheet_rows(TASKS_SHEET_NAME, [task_row_number])
    clear_work_ticket_cache()
    return deleted_tasks, deleted_activities


def clear_work_ticket_cache():
    """Clear only Work Ticket caches; do not clear the whole application cache."""
    try:
        load_tasks_data.clear()
    except Exception:
        pass
    try:
        load_task_activity_data.clear()
    except Exception:
        pass


def _parse_task_datetime(start_date_value, time_value):
    d = pd.to_datetime(start_date_value, dayfirst=True, errors="coerce")
    t = pd.to_datetime(str(time_value), errors="coerce")
    if pd.isna(d) or pd.isna(t):
        return None
    return datetime.combine(d.date(), t.time())


def _calc_minutes(start_date_value, start_time_value, end_time_value):
    start_dt = _parse_task_datetime(start_date_value, start_time_value)
    end_dt = _parse_task_datetime(start_date_value, end_time_value)
    if start_dt is None or end_dt is None:
        return 0.0
    if end_dt < start_dt:
        end_dt = end_dt + timedelta(days=1)
    return round(max((end_dt - start_dt).total_seconds() / 60, 0), 2)


def _task_priority_column(headers):
    for candidate in ["Task_Priority", "Priority", "Task_Duration"]:
        if any(_norm_sheet_col(h) == _norm_sheet_col(candidate) for h in headers):
            return candidate
    return "Task_Duration"


@st.cache_data(ttl=3600)
def get_task_process_options():
    """Return the same work categories used in KPI Process charts/forms.

    Work Tickets uses the KPI work-category list, not OEE process/machine
    process names. This keeps the task assignment dropdown aligned with
    the KPI Process donut chart categories such as Proizvodnja, Proces
    održavanje, Projekti, Kvalitet and Papirologija (Liste).
    """
    fallback = ["Proizvodnja", "Proces održavanje", "Projekti", "Kvalitet", "Papirologija (Liste)"]
    try:
        kpi_raw = load_worksheet(KPI_SHEET_ID, KPI_SHEET_NAME)
        kpi_raw = clean_columns(kpi_raw)
        category_col = None
        for col in kpi_raw.columns:
            if _norm_sheet_col(col) == _norm_sheet_col("Kategorija rada"):
                category_col = col
                break
        if category_col is not None:
            opts = sorted(kpi_raw[category_col].dropna().astype(str).str.strip().unique().tolist())
            opts = [x for x in opts if x and x.lower() not in ["nan", "none"]]
            if opts:
                return opts
    except Exception:
        pass
    return fallback


def _get_technician_email_map():
    tech_df, _ = load_technicians_master()
    if tech_df.empty:
        return {}, []
    active_mask = tech_df["Active"].astype(str).str.strip().str.upper().isin(["YES", "Y", "DA", "TRUE", "1"])
    tech_df = tech_df[active_mask].copy()
    names = tech_df["Technician_Name"].astype(str).str.strip().tolist()
    email_map = dict(zip(tech_df["Technician_Name"].astype(str).str.strip(), tech_df["Email"].astype(str).str.strip()))
    return email_map, names


def _get_current_user_technician_name():
    """Return the Technician_Name linked to the logged-in user.

    Non-admin users may create and record activities only for their own
    technician record. The link is primarily User&Password.Username ->
    Technicians.Username, with Full_Name -> Technician_Name as fallback.
    """
    try:
        username = str(current_user.get("username", "") or "").strip().casefold()
        full_name = str(current_user.get("full_name", "") or "").strip().casefold()
        tech_df, _ = load_technicians_master()
        if tech_df.empty:
            return ""
        active_mask = tech_df["Active"].astype(str).str.strip().str.upper().isin(["YES", "Y", "DA", "TRUE", "1"])
        tech_df = tech_df[active_mask].copy()

        if username:
            match = tech_df[tech_df["Username"].astype(str).str.strip().str.casefold().eq(username)]
            if not match.empty:
                return str(match.iloc[0]["Technician_Name"]).strip()

        if full_name:
            match = tech_df[tech_df["Technician_Name"].astype(str).str.strip().str.casefold().eq(full_name)]
            if not match.empty:
                return str(match.iloc[0]["Technician_Name"]).strip()
    except Exception:
        pass
    return ""


