        if isinstance(bn_date_range, tuple) and len(bn_date_range) == 2:
            bn_start_date = pd.to_datetime(bn_date_range[0])
            bn_end_date = pd.to_datetime(bn_date_range[1])
        else:
            bn_start_date = pd.to_datetime(bn_min_date)
            bn_end_date = pd.to_datetime(bn_max_date)
